```c
#include <stdio.h>
#include <stdint.h>

uint16_t float_to_float16(float f_val)
{
    uint32_t i_val = *(uint32_t *)&f_val; // cast the float pointer to an integer pointer and dereference it

    uint16_t sign = (i_val >> 16) & 0x8000; // extract the sign bit from the most significant bit of the integer value
    int16_t exponent = ((i_val >> 23) & 0xFF) - 127 + 15; // extract the exponent value and adjust it to FLOAT16 bias
    uint16_t mantissa = i_val & 0x007FFFFF; // extract the mantissa value

    // handle special cases: infinities and NaNs
    if (exponent == 0xFF - 127 + 15) {
        if (mantissa == 0) {
            // positive infinity
            exponent = 0x1F; // set all exponent bits to 1
        }
        else {
            // NaN
            exponent = 0x1F; // set all exponent bits to 1
            mantissa >>= 13; // shift the most significant 10 bits of the mantissa to the least significant bits
        }
    }
    else if (exponent <= 0) {
        // zero or denormalized numbers
        mantissa |= 0x00800000; // add the implied leading bit to the mantissa
        exponent = 0; // set the exponent to 0
        mantissa >>= -(exponent + 1); // shift the mantissa to the right by (-exponent + 1) bits
    }
    else {
        // normalized numbers
        exponent <<= 10; // shift the exponent value to the most significant bits of the FLOAT16 value
        mantissa >>= 13; // shift the most significant 13 bits of the mantissa to the least significant bits
    }

    uint16_t result = sign | exponent | mantissa; // combine the sign, exponent, and mantissa values to form the FLOAT16 value

    return result;
}

int main(void)
{
    float f_val = 1.875;

    uint16_t float16_val = float_to_float16(f_val);

    printf("The FLOAT16 representation of %f is: 0x%04X\n", f_val, float16_val);

    return 0;
}
```

